package com.infy.inventrack.inventory.client; import com.infy.inventrack.common.constants.InfyInvenTrackConstants; import com.infy.inventrack.common.dto.ProductResponse; import com.infy.inventrack.common.exception.DownstreamServiceException; import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker; import org.springframework.http.*; import org.springframework.stereotype.Component; import org.springframework.web.client.RestTemplate; @Component public class CatalogClient { private final RestTemplate rest; public CatalogClient(RestTemplate r){rest=r;} @CircuitBreaker(name="catalogService", fallbackMethod="fallbackProduct") public ProductResponse getProduct(String sku,String auth){ HttpHeaders h=new HttpHeaders(); if(auth!=null) h.set(HttpHeaders.AUTHORIZATION,auth); return rest.exchange("http://catalog-service/products/"+sku,HttpMethod.GET,new HttpEntity<>(h),ProductResponse.class).getBody(); } ProductResponse fallbackProduct(String sku,String auth,Throwable ex){ throw new DownstreamServiceException(InfyInvenTrackConstants.DOWNSTREAM_UNAVAILABLE.value()); } }
